/**
 * Email notification adapter — delivers notifications via email.
 *
 * Features:
 * - Template rendering: generates HTML and plain-text email bodies per notification type
 * - Recipient resolution: resolves user IDs or identifiers to email addresses
 * - Pluggable transport: swap InMemoryTransport for a real provider (SendGrid, SES, SMTP)
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Rendered email template output.
 */
export interface EmailTemplate {
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport abstraction for email delivery.
 * Implement this interface to plug in a real email provider.
 */
export interface EmailTransport {
  sendMail(options: {
    to: string;
    subject: string;
    html: string;
    text: string;
  }): Promise<{ messageId: string }>;
}

/**
 * A sent email record, for auditing and testing.
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  html: string;
  sentAt: Date;
  messageId: string;
}

/**
 * Resolves a recipient identifier (which may be a user ID, email, etc.)
 * to an email address. Returns null if the recipient cannot be resolved.
 */
export type RecipientResolver = (recipient: string) => Promise<string | null>;

/**
 * Default recipient resolver — treats the recipient as an email address if it
 * contains '@', otherwise returns null.
 */
export const defaultRecipientResolver: RecipientResolver = async (recipient: string) => {
  if (recipient.includes('@')) {
    return recipient;
  }
  return null;
};

/**
 * In-memory email transport for development and testing.
 */
export class InMemoryTransport implements EmailTransport {
  private nextId = 1;

  async sendMail(options: {
    to: string;
    subject: string;
    html: string;
    text: string;
  }): Promise<{ messageId: string }> {
    const messageId = `msg-${String(this.nextId++).padStart(4, '0')}`;
    return { messageId };
  }

  resetIdCounter(): void {
    this.nextId = 1;
  }
}

// --- Template rendering ---

const TEMPLATES: Record<NotificationType, (payload: NotificationPayload) => EmailTemplate> = {
  order_confirmation: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h1 style="color: #2563eb;">Order Confirmation</h1>',
      `<p>Hi,</p>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      payload.metadata?.orderId
        ? `<p><strong>Order ID:</strong> ${escapeHtml(String(payload.metadata.orderId))}</p>`
        : '',
      '<p>Thank you for your purchase!</p>',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #6b7280; font-size: 12px;">TaskFlow Pro</p>',
      '</div>',
    ].join('\n'),
    text: `Order Confirmation\n\n${payload.body}\n\nThank you for your purchase!\n\n-- TaskFlow Pro`,
  }),

  order_status_update: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h1 style="color: #2563eb;">Order Status Update</h1>',
      `<p>${escapeHtml(payload.body)}</p>`,
      '<p>You can track your order in your account dashboard.</p>',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #6b7280; font-size: 12px;">TaskFlow Pro</p>',
      '</div>',
    ].join('\n'),
    text: `Order Status Update\n\n${payload.body}\n\nYou can track your order in your account dashboard.\n\n-- TaskFlow Pro`,
  }),

  welcome: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h1 style="color: #2563eb;">Welcome to TaskFlow Pro!</h1>',
      `<p>${escapeHtml(payload.body)}</p>`,
      '<p>Get started by exploring your dashboard.</p>',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #6b7280; font-size: 12px;">TaskFlow Pro</p>',
      '</div>',
    ].join('\n'),
    text: `Welcome to TaskFlow Pro!\n\n${payload.body}\n\nGet started by exploring your dashboard.\n\n-- TaskFlow Pro`,
  }),

  account_updated: (payload) => ({
    subject: payload.subject,
    html: [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      '<h1 style="color: #2563eb;">Account Updated</h1>',
      `<p>${escapeHtml(payload.body)}</p>`,
      '<p>If you did not make this change, please contact support immediately.</p>',
      '<hr style="border: none; border-top: 1px solid #e5e7eb;" />',
      '<p style="color: #6b7280; font-size: 12px;">TaskFlow Pro</p>',
      '</div>',
    ].join('\n'),
    text: `Account Updated\n\n${payload.body}\n\nIf you did not make this change, please contact support immediately.\n\n-- TaskFlow Pro`,
  }),
};

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Render an email template for the given notification payload.
 */
export function renderTemplate(payload: NotificationPayload): EmailTemplate {
  const templateFn = TEMPLATES[payload.type];
  return templateFn(payload);
}

// --- EmailAdapter ---

let nextId = 1;

function generateEmailId(): string {
  return `email-${String(nextId++).padStart(4, '0')}`;
}

export function resetEmailIdCounter(): void {
  nextId = 1;
}

export interface EmailAdapterOptions {
  transport?: EmailTransport;
  recipientResolver?: RecipientResolver;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];
  private transport: EmailTransport;
  private recipientResolver: RecipientResolver;

  constructor(options?: EmailAdapterOptions) {
    this.transport = options?.transport ?? new InMemoryTransport();
    this.recipientResolver = options?.recipientResolver ?? defaultRecipientResolver;
  }

  /**
   * Send an email notification:
   * 1. Resolve recipient to an email address
   * 2. Render the template for the notification type
   * 3. Send via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const emailId = generateEmailId();

    // Step 1: Resolve recipient
    const resolvedEmail = await this.recipientResolver(payload.recipient);
    if (!resolvedEmail) {
      this.logger.error(`Cannot resolve recipient: ${payload.recipient}`);
      return {
        success: false,
        notificationId: emailId,
        channel: 'email',
        error: `Cannot resolve recipient: ${payload.recipient}`,
      };
    }

    // Step 2: Render template
    const template = renderTemplate(payload);

    this.logger.info(`Sending email to ${resolvedEmail}: ${template.subject}`);

    // Step 3: Send via transport
    try {
      const result = await this.transport.sendMail({
        to: resolvedEmail,
        subject: template.subject,
        html: template.html,
        text: template.text,
      });

      const email: SentEmail = {
        to: resolvedEmail,
        subject: template.subject,
        body: template.text,
        html: template.html,
        sentAt: new Date(),
        messageId: result.messageId,
      };

      this.sentEmails.push(email);

      return {
        success: true,
        notificationId: emailId,
        channel: 'email',
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Transport error: ${message}`);
      return {
        success: false,
        notificationId: emailId,
        channel: 'email',
        error: `Transport error: ${message}`,
      };
    }
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

