import { describe, it, expect, beforeEach, vi } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  renderTemplate,
  defaultRecipientResolver,
  resetEmailIdCounter,
} from '../../src/adapters/email.adapter.js';
import type {
  EmailTransport,
  RecipientResolver,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'email',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
    resetEmailIdCounter();
  });

  describe('send', () => {
    it('should send an email and return success', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.notificationId).toBe('email-0001');
    });

    it('should store sent emails for inspection', async () => {
      await adapter.send(makePayload());

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]?.messageId).toMatch(/^msg-/);
    });

    it('should generate sequential email IDs', async () => {
      const r1 = await adapter.send(makePayload());
      const r2 = await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      expect(r1.notificationId).toBe('email-0001');
      expect(r2.notificationId).toBe('email-0002');
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('recipient resolution', () => {
    it('should resolve email addresses directly', async () => {
      const result = await adapter.send(makePayload({ recipient: 'test@example.com' }));
      expect(result.success).toBe(true);
      expect(adapter.getSentEmails()[0]?.to).toBe('test@example.com');
    });

    it('should fail when recipient cannot be resolved', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user-123' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve recipient');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should use a custom recipient resolver', async () => {
      const resolver: RecipientResolver = async (recipient) => {
        if (recipient === 'user-1') return 'resolved@example.com';
        return null;
      };

      const customAdapter = new EmailAdapter({ recipientResolver: resolver });
      resetEmailIdCounter();

      const result = await customAdapter.send(makePayload({ recipient: 'user-1' }));

      expect(result.success).toBe(true);
      expect(customAdapter.getSentEmails()[0]?.to).toBe('resolved@example.com');
    });

    it('should fail with custom resolver returning null', async () => {
      const resolver: RecipientResolver = async () => null;
      const customAdapter = new EmailAdapter({ recipientResolver: resolver });

      const result = await customAdapter.send(makePayload({ recipient: 'unknown' }));
      expect(result.success).toBe(false);
    });
  });

  describe('template rendering', () => {
    it('should render order_confirmation template with HTML', async () => {
      await adapter.send(makePayload());

      const emails = adapter.getSentEmails();
      expect(emails[0]?.html).toContain('Order Confirmation');
      expect(emails[0]?.html).toContain('Thank you for your purchase');
      expect(emails[0]?.text).toContain('Order Confirmation');
    });

    it('should render order_status_update template', async () => {
      await adapter.send(
        makePayload({
          type: 'order_status_update',
          subject: 'Order Update: order-1',
          body: 'Your order status has changed from pending to confirmed.',
        }),
      );

      const emails = adapter.getSentEmails();
      expect(emails[0]?.html).toContain('Order Status Update');
      expect(emails[0]?.html).toContain('track your order');
      expect(emails[0]?.text).toContain('pending to confirmed');
    });

    it('should render welcome template', async () => {
      await adapter.send(
        makePayload({
          type: 'welcome',
          subject: 'Welcome to TaskFlow Pro',
          body: 'Welcome, Alice! Your account has been created.',
        }),
      );

      const emails = adapter.getSentEmails();
      expect(emails[0]?.html).toContain('Welcome to TaskFlow Pro');
      expect(emails[0]?.html).toContain('exploring your dashboard');
    });

    it('should render account_updated template', async () => {
      await adapter.send(
        makePayload({
          type: 'account_updated',
          subject: 'Account Updated',
          body: 'Your account has been updated.',
        }),
      );

      const emails = adapter.getSentEmails();
      expect(emails[0]?.html).toContain('Account Updated');
      expect(emails[0]?.html).toContain('contact support');
    });

    it('should escape HTML in body', async () => {
      await adapter.send(
        makePayload({
          body: '<script>alert("xss")</script>',
        }),
      );

      const emails = adapter.getSentEmails();
      expect(emails[0]?.html).not.toContain('<script>');
      expect(emails[0]?.html).toContain('&lt;script&gt;');
    });

    it('should include orderId metadata when present', async () => {
      await adapter.send(
        makePayload({
          metadata: { orderId: 'order-42' },
        }),
      );

      const emails = adapter.getSentEmails();
      expect(emails[0]?.html).toContain('order-42');
    });
  });

  describe('transport', () => {
    it('should use a custom transport', async () => {
      const sendMail = vi.fn().mockResolvedValue({ messageId: 'custom-id' });
      const transport: EmailTransport = { sendMail };

      const customAdapter = new EmailAdapter({ transport });
      resetEmailIdCounter();

      await customAdapter.send(makePayload());

      expect(sendMail).toHaveBeenCalledOnce();
      expect(sendMail).toHaveBeenCalledWith(
        expect.objectContaining({
          to: 'alice@example.com',
          subject: 'Order Confirmation: order-1',
        }),
      );
      expect(customAdapter.getSentEmails()[0]?.messageId).toBe('custom-id');
    });

    it('should handle transport errors gracefully', async () => {
      const transport: EmailTransport = {
        sendMail: vi.fn().mockRejectedValue(new Error('SMTP connection refused')),
      };

      const customAdapter = new EmailAdapter({ transport });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMTP connection refused');
      expect(customAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should handle non-Error transport throws', async () => {
      const transport: EmailTransport = {
        sendMail: vi.fn().mockRejectedValue('string error'),
      };

      const customAdapter = new EmailAdapter({ transport });
      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('string error');
    });
  });
});

describe('renderTemplate', () => {
  it('should return subject, html, and text for each notification type', () => {
    const types = ['order_confirmation', 'order_status_update', 'welcome', 'account_updated'] as const;

    for (const type of types) {
      const template = renderTemplate(makePayload({ type }));
      expect(template.subject).toBeTruthy();
      expect(template.html).toBeTruthy();
      expect(template.text).toBeTruthy();
      expect(template.html).toContain('TaskFlow Pro');
      expect(template.text).toContain('TaskFlow Pro');
    }
  });
});

describe('defaultRecipientResolver', () => {
  it('should return email addresses as-is', async () => {
    expect(await defaultRecipientResolver('test@example.com')).toBe('test@example.com');
  });

  it('should return null for non-email strings', async () => {
    expect(await defaultRecipientResolver('user-123')).toBeNull();
  });
});

describe('InMemoryTransport', () => {
  it('should generate sequential message IDs', async () => {
    const transport = new InMemoryTransport();

    const r1 = await transport.sendMail({ to: 'a@b.com', subject: 's', html: 'h', text: 't' });
    const r2 = await transport.sendMail({ to: 'a@b.com', subject: 's', html: 'h', text: 't' });

    expect(r1.messageId).toBe('msg-0001');
    expect(r2.messageId).toBe('msg-0002');
  });

  it('should reset ID counter', async () => {
    const transport = new InMemoryTransport();
    await transport.sendMail({ to: 'a@b.com', subject: 's', html: 'h', text: 't' });
    transport.resetIdCounter();
    const r = await transport.sendMail({ to: 'a@b.com', subject: 's', html: 'h', text: 't' });
    expect(r.messageId).toBe('msg-0001');
  });
});
